const body = $input.first().json.body ?? {};
const images = body.images;

if (!Array.isArray(images) || images.length < 1 || images.length > 5) {
  throw new Error('Expected body.images to contain 1-5 data URIs');
}

const binary = {};
for (const [index, uri] of images.entries()) {
  if (typeof uri !== 'string') throw new Error(`Image ${index + 1} is not a string`);

  const match = uri.match(/^data:(image\/(?:jpeg|png|webp));base64,(.+)$/s);
  if (!match) throw new Error(`Image ${index + 1} is not a supported image data URI`);

  const data = match[2].replace(/\s/g, '');
  if (!data || !/^[A-Za-z0-9+/]+={0,2}$/.test(data)) {
    throw new Error(`Image ${index + 1} contains invalid base64 data`);
  }

  const extension = match[1].split('/')[1].replace('jpeg', 'jpg');
  binary[`image_${index}`] = {
    data,
    mimeType: match[1],
    fileName: `item-${index + 1}.${extension}`,
  };
}

return [{ json: { imageCount: images.length }, binary }];

const response = $input.first().json;
const output = Array.isArray(response.output) ? response.output : [];
const raw = output
  .flatMap((block) => Array.isArray(block.content) ? block.content : [])
  .find((part) => part.type === 'output_text')?.text
  ?? response.message?.content
  ?? response.content
  ?? response.text;

if (typeof raw !== 'string') {
  return [{ json: { error: 'parse_failed', raw: null } }];
}

const cleaned = raw.replace(/^```json\s*|\s*```$/g, '').trim();
let listing;
try {
  listing = JSON.parse(cleaned);
} catch {
  return [{ json: { error: 'parse_failed', raw } }];
}

const valid = listing
  && typeof listing.title === 'string'
  && typeof listing.category === 'string'
  && (typeof listing.brand === 'string' || listing.brand === null)
  && ['A', 'B', 'C', 'D'].includes(listing.condition_grade)
  && Array.isArray(listing.defects)
  && listing.defects.every((defect) => typeof defect === 'string')
  && typeof listing.description === 'string'
  && Number.isFinite(listing.suggested_price_gbp)
  && listing.suggested_price_gbp >= 0
  && typeof listing.price_reasoning === 'string';

if (!valid) return [{ json: { error: 'parse_failed', raw } }];

return [{ json: listing }];
